            [
                'name' => 'drug_era_end_date',
                'type' => 'date',
                'required' => true,
                'description' => '',
                'etl_conventions' => 'The Drug Era End Date is the end date of the last Drug Exposure. The End Date of each Drug Exposure is either taken from the field drug_exposure_end_date or, as it is typically not available, inferred using the following rules: For pharmacy prescription data, the date when the drug was dispensed plus the number of days of supply are used to extrapolate the End Date for the Drug Exposure. Depending on the country-specific healthcare system, this supply information is either explicitly provided in the day_supply field or inferred from package size or similar information. For Procedure Drugs, usually the drug is administered on a single date (i.e., the administration date). A standard Persistence Window of 30 days (gap, slack) is permitted between two subsequent such extrapolated DRUG_EXPOSURE records to be considered to be merged into a single Drug Era.',
                'is_primary_key' => false,
                'is_foreign_key' => false,
                'fk_table' => null,
                'fk_domain' => null,
            ],
            [
                'name' => 'drug_exposure_count',
                'type' => 'integer',
                'required' => false,
                'description' => 'The count of grouped DRUG_EXPOSURE records that were included in the DRUG_ERA row',
                'etl_conventions' => '',
                'is_primary_key' => false,
                'is_foreign_key' => false,
                'fk_table' => null,
                'fk_domain' => null,
            ],
            [
                'name' => 'gap_days',
                'type' => 'integer',
                'required' => false,
                'description' => '',
                'etl_conventions' => 'The Gap Days determine how many total drug-free days are observed between all Drug Exposure events that contribute to a DRUG_ERA record. It is assumed that the drugs are “not stockpiled” by the patient, i.e. that if a new drug prescription or refill is observed (a new DRUG_EXPOSURE record is written), the remaining supply from the previous events is abandoned. The difference between Persistence Window and Gap Days is that the former is the maximum drug-free time allowed between two subsequent DRUG_EXPOSURE records, while the latter is the sum of actual drug-free days for the given Drug Era under the above assumption of non-stockpiling.',
                'is_primary_key' => false,
                'is_foreign_key' => false,
                'fk_table' => null,
                'fk_domain' => null,
            ],
